ALTER TABLE "agent_operations" ADD CONSTRAINT "agent_operations_text_check" CHECK (char_length("agent_operations"."idempotency_key") between 1 and 128 and char_length("agent_operations"."trace_id") between 1 and 128);--> statement-breakpoint
ALTER TABLE "conversation_messages" ADD CONSTRAINT "conversation_messages_content_check" CHECK (char_length("conversation_messages"."content") <= 64000);--> statement-breakpoint
ALTER TABLE "conversation_messages" ADD CONSTRAINT "conversation_messages_terminal_check" CHECK (("conversation_messages"."status" in ('completed', 'failed', 'cancelled', 'interrupted') and "conversation_messages"."completed_at" is not null) or ("conversation_messages"."status" in ('pending', 'streaming') and "conversation_messages"."completed_at" is null));--> statement-breakpoint
ALTER TABLE "conversations" ADD CONSTRAINT "conversations_text_check" CHECK (char_length("conversations"."owner_subject_id") between 1 and 160 and "conversations"."agent_profile_id" ~ '^[a-z][a-z0-9._-]{0,127}$' and ("conversations"."title" is null or char_length("conversations"."title") between 1 and 300));--> statement-breakpoint
ALTER TABLE "spaces" ADD CONSTRAINT "spaces_text_check" CHECK (char_length("spaces"."owner_subject_id") between 1 and 160 and char_length("spaces"."title") between 1 and 300);